const body = $input.first().json.body;

const prenom = body.prenom || body.first_name || body.firstName || '';
const nom = body.nom || body.last_name || body.lastName || '';
const email = body.email || '';
const telephone = body.telephone || body.phone || '';
const entreprise = body.entreprise || body.company || '';
const activite = body.activite || body.poste || body.job_title || '';
const budget = body.budget || '';
const besoin = body.besoin || body.need || body.message || '';
const urgence = body.urgence || body.timeline || '';
const source = body.source || 'site-web';
const date_reception = new Date().toISOString();

return [{
  json: {
    prenom,
    nom,
    email,
    telephone,
    entreprise,
    activite,
    budget,
    besoin,
    urgence,
    source,
    date_reception
  }
}];

