parameters.jsCode:
const response = $input.first().json;

let analysisText = '';
if (response.content && response.content.length > 0) {
  analysisText = response.content[0].text;
}

const scoreMatch = analysisText.match(/SCORE_BANT:(\d+)/);
const scoreBant = scoreMatch ? parseInt(scoreMatch[1]) : 0;

const isHot = scoreBant >= 60;
const classification = isHot ? 'LEAD CHAUD' : 'LEAD TIÈDE';

const leadData = $('Extraction Données JSON').first().json;

// Extraction email de réponse personnalisé
const emailMatch = analysisText.match(/## 5\. EMAIL DE RÉPONSE PERSONNALISÉ([\s\S]*?)(?=$|## \d)/);
const emailPersonnalise = emailMatch ? emailMatch[1].trim() : '';

return [{
  json: {
    score_bant: scoreBant,
    classification: classification,
    is_hot_lead: isHot,
    analyse_complete: analysisText,
    email_personnalise: emailPersonnalise,
    lead_prenom: leadData.prenom,
    lead_nom: leadData.nom,
    lead_email: leadData.email,
    lead_telephone: leadData.telephone,
    lead_entreprise: leadData.entreprise,
    lead_activite: leadData.activite,
    lead_besoin: leadData.besoin,
    date_reception: leadData.date_reception
  }
}];

const leadData = $('Extraction Score BANT').first().json;

return [{
  json: {
    status: 'lead_tiede_en_attente',
    message: `Lead tiède enregistré : ${leadData.lead_prenom} ${leadData.lead_nom} (Score: ${leadData.score_bant}/100). Séquence de relance J+2 déclenchée.`,
    score_bant: leadData.score_bant,
    classification: leadData.classification,
    lead_prenom: leadData.lead_prenom,
    lead_nom: leadData.lead_nom,
    lead_email: leadData.lead_email,
    lead_telephone: leadData.lead_telephone,
    lead_entreprise: leadData.lead_entreprise,
    lead_activite: leadData.lead_activite,
    lead_besoin: leadData.lead_besoin,
    date_reception: leadData.date_reception,
    date_relance_j2: new Date(Date.now() + 2 * 24 * 60 * 60 * 1000).toISOString(),
    date_relance_j5: new Date(Date.now() + 5 * 24 * 60 * 60 * 1000).toISOString()
  }
}];
